#!/bin/bash
echo "=== FlipSlab Engine - Update Landing Page ==="

# Detectar directorio del proyecto
PROJECT_DIR=""
if [ -d "/opt/gradeprophet" ]; then
    PROJECT_DIR="/opt/gradeprophet"
elif [ -d "/home/gradeprophet" ]; then
    PROJECT_DIR="/home/gradeprophet"
else
    echo "ERROR: No se encontro el directorio del proyecto"
    exit 1
fi

echo "Directorio: $PROJECT_DIR"

# Backup del archivo actual
LANDING_FILE="$PROJECT_DIR/frontend/src/components/LandingPage.jsx"
if [ -f "$LANDING_FILE" ]; then
    cp "$LANDING_FILE" "$LANDING_FILE.bak"
    echo "Backup creado: LandingPage.jsx.bak"
fi

# Escribir el archivo actualizado
echo "Actualizando LandingPage.jsx..."
base64 -d << 'EOF' > "$LANDING_FILE"

EOF

echo "Archivo actualizado!"

# Rebuild frontend
echo "Rebuilding frontend..."
cd "$PROJECT_DIR/frontend"
npm run build 2>/dev/null || yarn build 2>/dev/null

echo ""
echo "=== Update completo! ==="
echo "Cambios aplicados:"
echo "  - Tarjeta de Brady mas grande y al mismo nivel que Kobe"  
echo "  - Seccion Features con imagenes generadas por AI"
echo "  - Menos espacio entre Hero y Features"
echo ""
echo "Refresca tu navegador para ver los cambios."
